// W3 — Build Input
// Edita los valores de `input` para probar distintos payloads.
//
// CONVENCIONES DEV:
//   - canal y id_evento solo se usan para id_evento_dev (trazabilidad de pruebas)
//   - W3 NO genera idempotency_key. La función registrar_pago() no la espera.
//     En producción, el webhook de MercadoPago debe deduplicar por payment_id
//     ANTES de llamar a W3.
//   - source_event fijo: "n8n_w03_registrar_pago_manual"
//
// REFERENCIA (uno u otro, no ambos):
//   - id_pre_reserva: pago de seña sobre pre-reserva activa
//   - id_reserva: pago posterior a la confirmación (saldo, extra, etc.)
//
// VALORES ACEPTADOS POR CHECK CONSTRAINT EN `pagos`:
//   - tipo:       'sena' | 'saldo' | 'extra' | 'reembolso' | 'ajuste'
//   - medio_pago: 'transferencia_bancaria' | 'transferencia_mp' | 'mp_link' | 'cripto' | 'efectivo'
//
// ESTADO INICIAL:
//   - Vacío -> queda en 'en_revision' (default para pagos manuales sin verificación).
//   - 'confirmado' + monto_recibido = monto_esperado -> queda confirmado, validado por sistema_auto.
//     Solo usar 'confirmado' cuando viene de MP webhook con confirmación, no para pruebas manuales.

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (solo para trazabilidad de pruebas)
  canal: "manual_dev",
  id_evento: "test_w03_001",

  // Referencia (uno u otro, no ambos)
  id_pre_reserva: 25,
  id_reserva: null,

  // Datos del pago
  tipo: "sena",
  medio_pago: "transferencia_mp",
  monto_esperado: 50000,
  monto_recibido: 50000,
  moneda: "ARS",
  es_automatico: false,

  // Estado inicial (vacío = en_revision; "confirmado" solo para flujos automáticos verificados)
  estado_inicial: "",

  // Opcionales
  comprobante_url: "",
  referencia_externa: "",
  notas: "Pago de prueba W3 Test 1",
  proveedor: "",
  cuenta_destino: "",
  validado_por: ""
};
// =============================================

return [{ json: input }];

// W3 — Build Payload
// Toma el input editable de Build Input y construye:
//   1. source_event (convención 6C v1.2 Sección 5.5):
//        n8n_w03_registrar_pago_manual
//   2. id_evento_dev: solo para trazabilidad de pruebas en el wrapper
//      (NO se manda a la función SQL).
//   3. payload JSONB según contrato de registrar_pago(jsonb).
//
// CONTRATO PAYLOAD: ver firma real de registrar_pago en 6B_SCHEMA_SQL.md
// v1.7.1 (Bloque correspondiente).
//
// CAMPOS OBLIGATORIOS (la función rebota con 'payload_invalido' si faltan):
//   tipo, medio_pago, monto_esperado, monto_recibido, source_event
//   + al menos uno de id_pre_reserva / id_reserva
//
// CAMPOS OPCIONALES (la función los procesa con NULLIF):
//   moneda (default 'ARS'), es_automatico (default false), estado_inicial,
//   comprobante_url, referencia_externa, tx_hash, validado_por, notas,
//   proveedor, cuenta_destino
//
// W3 NO genera idempotency_key. La función no la espera ni la valida.
// En producción, la deduplicación es responsabilidad del webhook caller.
//
// NORMALIZACIÓN DEFENSIVA (W3 v1.1):
// Aplicamos nv() a TODOS los campos obligatorios (incluyendo tipo, medio_pago,
// monto_esperado, monto_recibido), no solo a los opcionales. Razón:
// registrar_pago() NO aplica NULLIF a 'tipo' ni 'medio_pago', por lo que un
// string vacío "" pasa la validación inicial y termina chocando contra el
// CHECK constraint chk_pagos_tipo / chk_pagos_medio, generando un error
// crudo de Postgres en vez de un JSONB controlado.
// Al mandar null explícito desde n8n, payload->>'tipo' devuelve NULL real
// y la validación devuelve {ok:false, error:'payload_invalido'} limpio.
//
// Pendiente futuro: hardening de registrar_pago() para aplicar
// NULLIF(TRIM(...), '') en campos obligatorios de texto. Registrado en
// Pendiente_pre_produccion.md.

const input = $input.first().json;

const source_event = 'n8n_w03_registrar_pago_manual';

// id_evento_dev: trazabilidad de la prueba, queda en el wrapper externo,
// NO se manda a la función SQL.
const id_evento_dev = `${input.canal}_${input.id_evento}`;

// Helper: convierte string vacío en null, deja el resto tal cual
const nv = (v) => (v === '' || v === undefined ? null : v);

const payload = {
  // Referencias (uno u otro, no ambos)
  id_pre_reserva: input.id_pre_reserva,
  id_reserva: input.id_reserva,

  // Obligatorios (con normalización defensiva por bug de validación SQL)
  tipo: nv(input.tipo),
  medio_pago: nv(input.medio_pago),
  monto_esperado: nv(input.monto_esperado),
  monto_recibido: nv(input.monto_recibido),
  source_event,

  // Opcionales
  moneda: input.moneda,
  es_automatico: input.es_automatico,
  estado_inicial: nv(input.estado_inicial),
  comprobante_url: nv(input.comprobante_url),
  referencia_externa: nv(input.referencia_externa),
  tx_hash: null,
  notas: nv(input.notas),
  proveedor: nv(input.proveedor),
  cuenta_destino: nv(input.cuenta_destino),
  validado_por: nv(input.validado_por)
};

return [{
  json: {
    payload,
    source_event,
    id_evento_dev,
    input  // se preserva para trazabilidad en Build Response
  }
}];

// W3 — Build Response
// Interpreta el JSONB que devuelve registrar_pago() y arma el wrapper externo.
//
// Contrato de salida de la función:
//   - happy:           { ok: true, id_pago, estado: 'en_revision'|'confirmado' }
//   - v1.3 (terminal): { ok: true, id_pago, estado: 'en_revision',
//                        warning: 'prereserva_no_activa',
//                        prereserva_estado: '<estado_terminal>' }
//   - error:           { ok: false, error: '<codigo>', ...detalle }
//
// CONVENCIONES DEL WRAPPER:
//   - ok = resultado.ok (la función devuelve ok=true también para casos v1.3).
//   - error solo se llena cuando resultado.ok = false.
//   - id_evento_dev se incluye para trazabilidad de qué prueba generó qué pago.
//   - result siempre lleva el JSONB completo de la función.
//   - warning del caso v1.3 se eleva al nivel del wrapper para que sea visible
//     sin tener que entrar a result.
//
// W3 NO incluye idempotency_key en el wrapper (no aplica).

const buildPayload = $('Build Payload').first().json;
const pgItem = items[0]?.json;
const resultado = pgItem?.resultado;

if (!resultado || typeof resultado !== 'object') {
  return [{
    json: {
      ok: false,
      workflow: 'vita_w03_registrar_pago_supabase',
      source_event: buildPayload.source_event,
      id_evento_dev: buildPayload.id_evento_dev,
      error: 'sin_respuesta_de_funcion',
      warning: null,
      result: null,
      executed_at: new Date().toISOString()
    }
  }];
}

const ok = resultado.ok === true;

return [{
  json: {
    ok,
    workflow: 'vita_w03_registrar_pago_supabase',
    source_event: buildPayload.source_event,
    id_evento_dev: buildPayload.id_evento_dev,
    error: ok ? null : (resultado.error || 'error_desconocido'),
    warning: resultado.warning || null,
    result: resultado,
    executed_at: new Date().toISOString()
  }
}];
